import type { OpenClawPluginApi } from "openclaw/plugin-sdk";
import { emptyPluginConfigSchema } from "openclaw/plugin-sdk";
import { xiaoicePlugin } from "./src/channel.js";
import { createWebhookHandler } from "./src/webhook.js";

let webhookHandler: ReturnType<typeof createWebhookHandler> | null = null;

const plugin = {
  id: "xiaoice",
  name: "XiaoIce",
  description: "OpenClaw XiaoIce channel plugin",
  configSchema: emptyPluginConfigSchema(),
  register(api: OpenClawPluginApi) {
    // 注册 Channel
    api.registerChannel({ plugin: xiaoicePlugin });

    // 注册 Webhook 处理
    webhookHandler = createWebhookHandler(api.runtime);
    api.registerHttpHandler(async (req) => {
      if (req.url.includes("/webhooks/xiaoice")) {
        return webhookHandler!(req);
      }
      return new Response("Not found", { status: 404 });
    });
  },
};

export default plugin;

import type { OpenClawRuntime } from "openclaw/plugin-sdk";
import crypto from "crypto";
import type { WebhookPayload } from "./types.js";
import { resolveXiaoiceAccount } from "./accounts.js";

export function createWebhookHandler(runtime: OpenClawRuntime) {
  return async function handleXiaoiceWebhook(req: Request): Promise<Response> {
    try {
      // 获取 path 参数 accountId
      const url = new URL(req.url);
      const pathParts = url.pathname.split("/").filter(Boolean);
      const accountId = pathParts[pathParts.length - 1];

      // 解析 body
      const body = await req.json() as WebhookPayload;
      const { messageId, conversationId, userId, text, timestamp } = body;

      // 验证签名
      const signature = req.headers.get("X-Signature");
      const account = resolveXiaoiceAccount({ 
        cfg: runtime.config, 
        accountId 
      });

      if (account.config.webhookSecret && signature) {
        const expectedSig = crypto
          .createHmac("sha256", account.config.webhookSecret)
          .update(JSON.stringify(body))
          .digest("hex");

        if (signature !== expectedSig) {
          return new Response("Invalid signature", { status: 401 });
        }
      }

      // 调用 OpenClaw 处理消息
      // 这里需要根据实际 API 调整
      runtime.logger?.info(`Received message from ${userId}: ${text}`);

      return new Response(JSON.stringify({
        ok: true,
        messageId,
      }), {
        status: 200,
        headers: { "Content-Type": "application/json" },
      });

    } catch (error) {
      runtime.logger?.error(`Webhook error: ${error}`);
      return new Response("Internal error", { status: 500 });
    }
  };
}

import {
  buildChannelConfigSchema,
  DEFAULT_ACCOUNT_ID,
  getChatChannelMeta,
} from "openclaw/plugin-sdk";
import type { ChannelPlugin } from "openclaw/plugin-sdk";
import type { OpenClawConfig } from "openclaw/plugin-sdk";
import {
  listXiaoiceAccountIds,
  resolveXiaoiceAccount,
  resolveDefaultXiaoiceAccountId,
  type ResolvedXiaoiceAccount,
} from "./accounts.js";
import { sendXiaoiceMessage } from "./api.js";

const meta = getChatChannelMeta("xiaoice");

export const xiaoicePlugin: ChannelPlugin<ResolvedXiaoiceAccount> = {
  id: "xiaoice",
  meta: { ...meta },
  capabilities: {
    chatTypes: ["direct"],
  },
  configSchema: buildChannelConfigSchema({
    type: "object",
    properties: {
      apiBaseUrl: { type: "string" },
      apiKey: { type: "string" },
      webhookSecret: { type: "string" },
    },
  }),
  config: {
    listAccountIds: (cfg) => listXiaoiceAccountIds(cfg),
    resolveAccount: (cfg, accountId) => resolveXiaoiceAccount({ cfg, accountId }),
    defaultAccountId: (cfg) => resolveDefaultXiaoiceAccountId(cfg),
    isConfigured: (account) => !!account.config.apiBaseUrl && !!account.config.apiKey,
    describeAccount: (account) => ({
      accountId: account.accountId,
      name: account.name,
      enabled: account.enabled,
      configured: !!account.config.apiBaseUrl && !!account.config.apiKey,
      credentialSource: account.credentialSource,
    }),
  },
  outbound: {
    deliveryMode: "direct",
    sendText: async ({ cfg, accountId, text, to }) => {
      const account = resolveXiaoiceAccount({ cfg, accountId });
      const result = await sendXiaoiceMessage({
        account,
        conversationId: to || "default",
        text,
      });

      if (!result.ok) {
        throw new Error(result.error);
      }

      return {
        channel: "xiaoice",
        messageId: `msg_${Date.now()}`,
        chatId: to || "default",
      };
    },
  },
};

