import type { ResolvedXiaoiceAccount } from "./types.js";
import type { XiaoiceOutboundMessage, XiaoiceStreamEvent, XiaoiceStreamHandler } from "./types.js";

/**
 * 发送消息（非流式）
 */
export async function sendXiaoiceMessage({
  account,
  conversationId,
  text,
}: {
  account: ResolvedXiaoiceAccount;
  conversationId: string;
  text: string;
}): Promise<{ ok: boolean; error?: string }> {
  const { config } = account;

  if (!config.apiBaseUrl || !config.apiKey) {
    return { ok: false, error: "Missing apiBaseUrl or apiKey" };
  }

  try {
    const response = await fetch(`${config.apiBaseUrl}/send`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Bearer ${config.apiKey}`,
      },
      body: JSON.stringify({
        conversationId,
        text,
      } as XiaoiceOutboundMessage),
    });

    if (!response.ok) {
      return { 
        ok: false, 
        error: `HTTP ${response.status}: ${response.statusText}` 
      };
    }

    return { ok: true };
  } catch (error) {
    return { 
      ok: false, 
      error: error instanceof Error ? error.message : "Unknown error" 
    };
  }
}

/**
 * 发送消息（流式 SSE）
 * 返回 ReadableStream 用于流式处理
 */
export async function sendXiaoiceMessageStream({
  account,
  conversationId,
  text,
  onChunk,
}: {
  account: ResolvedXiaoiceAccount;
  conversationId: string;
  text: string;
  onChunk?: (event: XiaoiceStreamEvent) => void | Promise<void>;
}): Promise<{ ok: boolean; error?: string; stream?: ReadableStream<Uint8Array> }> {
  const { config } = account;

  if (!config.apiBaseUrl || !config.apiKey) {
    return { ok: false, error: "Missing apiBaseUrl or apiKey" };
  }

  try {
    const response = await fetch(`${config.apiBaseUrl}/send/stream`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Accept": "text/event-stream",
        "Authorization": `Bearer ${config.apiKey}`,
      },
      body: JSON.stringify({
        conversationId,
        text,
      } as XiaoiceOutboundMessage),
    });

    if (!response.ok) {
      return { 
        ok: false, 
        error: `HTTP ${response.status}: ${response.statusText}` 
      };
    }

    const stream = response.body;

    if (!stream) {
      return { ok: false, error: "No stream returned" };
    }

    // 创建转换流处理 SSE
    const transformer = new TransformStream<Uint8Array, XiaoiceStreamEvent>({
      transform(chunk, controller) {
        const decoder = new TextDecoder();
        const text = decoder.decode(chunk, { stream: true });

        // 解析 SSE 格式
        // data: {"id":"...","replyText":"..."}
        const lines = text.split("\n");
        for (const line of lines) {
          if (line.startsWith("data: ")) {
            const data = line.slice(6).trim();
            if (data && data !== "[DONE]") {
              try {
                const event = JSON.parse(data) as XiaoiceStreamEvent;
                // 调用回调
                if (onChunk) {
                  onChunk(event);
                }
                controller.enqueue(event);
              } catch (e) {
                // 忽略解析错误
              }
            }
          }
        }
      },
    });

    return { 
      ok: true, 
      stream: stream.pipeThrough(transformer) 
    };
  } catch (error) {
    return { 
      ok: false, 
      error: error instanceof Error ? error.message : "Unknown error" 
    };
  }
}

export type XiaoiceCredentialSource = "inline" | "none";

export type XiaoiceAccountConfig = {
  apiBaseUrl?: string;
  apiKey?: string;
  webhookSecret?: string;
};

export type ResolvedXiaoiceAccount = {
  accountId: string;
  name?: string;
  enabled: boolean;
  config: XiaoiceAccountConfig;
  credentialSource: XiaoiceCredentialSource;
};

export type XiaoiceMessage = {
  messageId: string;
  conversationId: string;
  userId: string;
  text: string;
  timestamp: number;
};

export type XiaoiceOutboundMessage = {
  conversationId: string;
  text: string;
};

export type WebhookPayload = {
  messageId: string;
  conversationId: string;
  userId: string;
  text: string;
  timestamp: number;
};

// SSE 流式消息格式
export type XiaoiceStreamEvent = {
  id: string;
  traceId?: string;
  sessionId?: string;
  askText: string;
  replyText: string;
  replyType: "FAQ" | "Doc" | "Llm" | "Fallback";
  timestamp: number;
  replyPayload?: Record<string, unknown>;
  extra?: Record<string, string>;
};

// SSE 流式回调类型
export type XiaoiceStreamHandler = (event: XiaoiceStreamEvent) => void | Promise<void>;

import {
  buildChannelConfigSchema,
  DEFAULT_ACCOUNT_ID,
  getChatChannelMeta,
} from "openclaw/plugin-sdk";
import type { ChannelPlugin } from "openclaw/plugin-sdk";
import type { OpenClawConfig } from "openclaw/plugin-sdk";
import {
  listXiaoiceAccountIds,
  resolveXiaoiceAccount,
  resolveDefaultXiaoiceAccountId,
  type ResolvedXiaoiceAccount,
} from "./accounts.js";
import { sendXiaoiceMessage, sendXiaoiceMessageStream } from "./api.js";

const meta = getChatChannelMeta("xiaoice");

export const xiaoicePlugin: ChannelPlugin<ResolvedXiaoiceAccount> = {
  id: "xiaoice",
  meta: { ...meta },
  capabilities: {
    chatTypes: ["direct"],
  },
  configSchema: buildChannelConfigSchema({
    type: "object",
    properties: {
      apiBaseUrl: { type: "string" },
      apiKey: { type: "string" },
      webhookSecret: { type: "string" },
    },
  }),
  config: {
    listAccountIds: (cfg) => listXiaoiceAccountIds(cfg),
    resolveAccount: (cfg, accountId) => resolveXiaoiceAccount({ cfg, accountId }),
    defaultAccountId: (cfg) => resolveDefaultXiaoiceAccountId(cfg),
    isConfigured: (account) => !!account.config.apiBaseUrl && !!account.config.apiKey,
    describeAccount: (account) => ({
      accountId: account.accountId,
      name: account.name,
      enabled: account.enabled,
      configured: !!account.config.apiBaseUrl && !!account.config.apiKey,
      credentialSource: account.credentialSource,
    }),
  },
  // 流式相关配置
  streaming: {
    // 支持流式回复
    supported: true,
    // 构建流式上下文
    buildToolContext: ({ context }) => ({
      conversationId: context.To || "default",
    }),
  },
  outbound: {
    deliveryMode: "direct",
    sendText: async ({ cfg, accountId, text, to, stream }) => {
      const account = resolveXiaoiceAccount({ cfg, accountId });
      const conversationId = to || "default";

      // 如果需要流式返回
      if (stream) {
        const result = await sendXiaoiceMessageStream({
          account,
          conversationId,
          text,
          onChunk: async (event) => {
            // 将流式事件写入响应
            const data = `data: ${JSON.stringify(event)}\n\n`;
            await stream.writer.write(new TextEncoder().encode(data));
          },
        });

        if (!result.ok) {
          throw new Error(result.error);
        }

        return {
          channel: "xiaoice",
          messageId: `msg_${Date.now()}`,
          chatId: conversationId,
        };
      }

      // 普通非流式发送
      const result = await sendXiaoiceMessage({
        account,
        conversationId,
        text,
      });

      if (!result.ok) {
        throw new Error(result.error);
      }

      return {
        channel: "xiaoice",
        messageId: `msg_${Date.now()}`,
        chatId: conversationId,
      };
    },
  },
};

